css:
@font-face {
    font-family: 'YourFont';
    src: url('https://widgets.sociablekit.com/google-reviews/fontawesome-webfont.woff2') format('woff2'),
         url('https://widgets.sociablekit.com/google-reviews/fontawesome-webfont.woff2') format('woff');
