}
body .sk-ww-google-reviews * { box-sizing: border-box; }

body .sk-ww-google-reviews .sk-arrow {
    border: solid black;
    border-width: 0 3px 3px 0;
    display: inline-block;
    padding: 8px;
}

body .sk-ww-google-reviews .sk-reviewer-pic img {
    margin-top: unset;
    margin-bottom: unset;
}

body .sk-ww-google-reviews .sk-arrow-right {
    transform: rotate(-45deg);
    -webkit-transform: rotate(-45deg);
}

body .sk-ww-google-reviews .sk-arrow-left {
    transform: rotate(135deg);
    -webkit-transform: rotate(135deg);
}

body .sk-ww-google-reviews .swiper-button-next,body .sk-ww-google-reviews .swiper-button-prev{
    border: 0px !important;
    background: transparent;
    background-image:none !important;
