}

.sk_reviews_grid .sk_post_img{ width:100%; }
.sk_reviews_grid .sk_link_img{ padding:0 1px; }


/* ---- sk_reviews_grid ---- */

.sk_reviews_grid {
  max-width: 100%;
}


/* clearfix */
.sk_reviews_grid:after {
  content: '';
  display: block;
  clear: both;
}

/* ---- sk_reviews_grid-item ---- */

.sk_reviews_grid-sizer,
.sk_reviews_grid-item {
  width: 25%;
}

.sk_reviews_grid-item {
  float: left;
  padding:8px;
  height:auto;
  overflow:hidden;
}

.sk_reviews_grid-item--width2 { width:  40%; }
.sk_reviews_grid-item--width3 { width:  60%; }

.sk_reviews_grid-item--height2 { height: 200px; }
.sk_reviews_grid-item--height3 { height: 260px; }
.sk_reviews_grid-item--height4 { height: 360px; }

.sk_reviews_grid-content{
    cursor: default !important;
    overflow: hidden;
    text-align: left;
    border-radius: 8px;
    box-shadow: 0 0 0 1px rgba(0, 0, 0, .15) inset, 0 3px 6px rgba(0, 0, 0, .1);
    -webkit-box-shadow: 0 2px 5px rgba(0,0,0,0.3);
    display: flex;
    flex-direction: column;
}

@supports (-webkit-hyphens: none) and (not (-ms-ime-align: auto)) {
    /* Darken box shadow on Safari Devices */
    .sk_reviews_grid-content{
        box-shadow: 0 0 0 1px rgba(0, 0, 0, .15) inset, 0 3px 6px rgba(0, 0, 0, .1);
        -webkit-box-shadow: 0 2px 5px rgba(0,0,0,0.3);
    }
}

